            <b>{v().ok ? "PASS - bug is fixed" : "FAIL - bug reproduced"}</b>
            <p>Expected both cases to render "Pay now".</p>
            <pre>{v().actual}</pre>
          </section>
        )}
      </Show>
    </main>
  );
}

